import React, { useState, useEffect, useRef } from 'react';
import WaterWatchApi from '../api/waterwatchApi';

const WaterWatchMap = () => {
  const canvasRef = useRef(null);
  const mapWrapRef = useRef(null);

  const [stations, setStations] = useState([]);
  const [selectedStation, setSelectedStation] = useState(null);
  const [layer, setLayer] = useState('sat');
  const [coordinates, setCoordinates] = useState('41.74°N  21.78°E');
  const [hoveredStation, setHoveredStation] = useState(null);
  const [tipPos, setTipPos] = useState({ x: 0, y: 0 });
  const [alert, setAlert] = useState(null);
  const [loading, setLoading] = useState(false);
  const [animationPhase, setAnimationPhase] = useState(0);

  const api = new WaterWatchApi();

  // Station data from HTML
  const ST = [
    { id: 'vardar_vs', n: 'Vardar: Veles to Skopje', r: 'Vardar', la: 41.7157, lo: 21.7758, rk: 5, par: 'Hg, PCBs', wfd: 'Poor', sg: 3.7, src: 'Factory upstream' },
    { id: 'treska_km', n: 'Treska: Kozjak to Matka', r: 'Treska', la: 41.98, lo: 21.21, rk: 4, par: 'BOD5, NH4', wfd: 'Poor', sg: 2.9, src: 'Urban runoff' },
    { id: 'ohrid_s', n: 'Ohrid Lake: Studencista', r: 'Ohrid', la: 41.08, lo: 20.72, rk: 3, par: 'PO4, E.coli', wfd: 'Moderate', sg: 1.8, src: 'Urban' },
  ];

  const RC = { 5: '#E24B4A', 4: '#EF9F27', 3: '#a8c340', 2: '#3db87a' };
  const RL = { 5: 'Critical 5/5', 4: 'Very high 4/5', 3: 'High 3/5', 2: 'Moderate 2/5' };

  const BNDS = { mla: 40.55, xla: 42.45, mlo: 20.1, xlo: 23.2 };

  const RIVERS = [
    { pts: [[42.15, 21.43], [42.05, 21.52], [42.0, 21.60], [41.85, 21.75], [41.72, 21.77], [41.58, 21.95], [41.47, 22.02], [41.41, 22.05], [41.14, 22.18]], rk: 5 },
    { pts: [[41.98, 21.21], [41.93, 21.25], [41.87, 21.30]], rk: 3 },
    { pts: [[42.13, 21.72], [42.05, 21.77], [41.99, 21.82]], rk: 4 },
    { pts: [[41.90, 22.18], [41.85, 22.28], [41.74, 22.19], [41.65, 22.19]], rk: 4 },
    { pts: [[41.52, 20.96], [41.39, 21.15], [41.22, 21.28], [41.03, 21.35]], rk: 4 },
    { pts: [[41.65, 20.52], [41.58, 20.57], [41.52, 20.52]], rk: 2 },
  ];

  const LAKES = [
    [[41.08, 20.72], [40.95, 20.72], [40.88, 20.82], [40.95, 20.92], [41.08, 20.87]],
    [[40.85, 20.85], [40.78, 20.88], [40.75, 20.98], [40.82, 21.05], [40.88, 20.95]],
    [[41.21, 22.65], [41.16, 22.65], [41.14, 22.75], [41.20, 22.78], [41.24, 22.72]],
    [[41.63, 20.67], [41.58, 20.66], [41.56, 20.76], [41.62, 20.75]],
  ];

  const CITIES = [
    { n: 'Skopje', la: 42.0, lo: 21.43 },
    { n: 'Veles', la: 41.72, lo: 21.78 },
    { n: 'Bitola', la: 41.03, lo: 21.33 },
    { n: 'Ohrid', la: 41.12, lo: 20.80 },
    { n: 'Kumanovo', la: 42.13, lo: 21.72 },
    { n: 'Shtip', la: 41.74, lo: 22.20 },
    { n: 'Kochani', la: 41.88, lo: 22.41 },
    { n: 'Tetovo', la: 42.01, lo: 20.97 },
    { n: 'Debar', la: 41.52, lo: 20.53 },
  ];

  const p2c = (la, lo, W, H) => [
    ((lo - BNDS.mlo) / (BNDS.xlo - BNDS.mlo)) * W,
    (1 - (la - BNDS.mla) / (BNDS.xla - BNDS.mla)) * H,
  ];

  const c2p = (x, y, W, H) => [
    BNDS.xla - (y / H) * (BNDS.xla - BNDS.mla),
    BNDS.mlo + (x / W) * (BNDS.xlo - BNDS.mlo),
  ];

  const drawMap = () => {
    const canvas = canvasRef.current;
    if (!canvas) return;

    const ctx = canvas.getContext('2d');
    const W = canvas.width;
    const H = canvas.height;

    // Background
    if (layer === 'ndwi') {
      ctx.fillStyle = '#020810';
      ctx.fillRect(0, 0, W, H);
    } else {
      ctx.fillStyle = '#060f1c';
      ctx.fillRect(0, 0, W, H);
      for (let i = 0; i < 18; i++) {
        for (let j = 0; j < 12; j++) {
          const ns = Math.sin(i * 3.3 + j * 5.7) * Math.cos(i * 1.7 - j * 2.3);
          if (ns > 0.15) {
            ctx.fillStyle = `rgba(12,55,18,${ns * 0.07})`;
            ctx.fillRect((i / 18) * W, (j / 12) * H, W / 18 + 1, H / 12 + 1);
          }
        }
      }
    }

    // Grid
    ctx.strokeStyle = 'rgba(255,255,255,0.022)';
    ctx.lineWidth = 0.5;
    for (let la = 41; la <= 42.5; la += 0.5) {
      const [, y] = p2c(la, BNDS.mlo, W, H);
      ctx.beginPath();
      ctx.moveTo(0, y);
      ctx.lineTo(W, y);
      ctx.stroke();
    }
    for (let lo = 20.5; lo <= 23; lo += 0.5) {
      const [x] = p2c(BNDS.mla, lo, W, H);
      ctx.beginPath();
      ctx.moveTo(x, 0);
      ctx.lineTo(x, H);
      ctx.stroke();
    }

    // Grid labels
    ctx.fillStyle = 'rgba(60,110,170,0.3)';
    ctx.font = '9px monospace';
    for (let la = 41; la <= 42; la += 0.5) {
      const [, y] = p2c(la, BNDS.mlo + 0.05, W, H);
      ctx.fillText(la.toFixed(1) + 'N', 3, y - 1);
    }
    for (let lo = 21; lo <= 23; lo++) {
      const [x] = p2c(BNDS.mla + 0.02, lo, W, H);
      ctx.fillText(lo + 'E', x + 2, H - 4);
    }

    // Lakes
    LAKES.forEach(lk => {
      ctx.beginPath();
      const [sx, sy] = p2c(lk[0][0], lk[0][1], W, H);
      ctx.moveTo(sx, sy);
      lk.slice(1).forEach(([la, lo]) => {
        const [x, y] = p2c(la, lo, W, H);
        ctx.lineTo(x, y);
      });
      ctx.closePath();
      ctx.fillStyle = layer === 'ndwi' ? 'rgba(0,130,255,0.75)' : 'rgba(20,85,175,0.6)';
      ctx.fill();
      ctx.strokeStyle = '#2a6aaa';
      ctx.lineWidth = 0.8;
      ctx.stroke();
    });

    // Rivers
    RIVERS.forEach(rv => {
      if (rv.pts.length < 2) return;
      const col = layer === 'risk' ? RC[rv.rk] : layer === 'ndwi' ? '#00c4ff' : '#1a70d0';
      const widths = layer === 'ndwi' ? [8, 4, 2] : [5, 2, 1];
      widths.forEach((w, wi) => {
        ctx.beginPath();
        const [sx, sy] = p2c(rv.pts[0][0], rv.pts[0][1], W, H);
        ctx.moveTo(sx, sy);
        rv.pts.slice(1).forEach(([la, lo]) => {
          const [x, y] = p2c(la, lo, W, H);
          ctx.lineTo(x, y);
        });
        if (wi === 0) ctx.strokeStyle = layer === 'ndwi' ? 'rgba(0,180,255,0.35)' : col + '66';
        else if (wi === 1) ctx.strokeStyle = layer === 'ndwi' ? 'rgba(0,200,255,0.65)' : col;
        else ctx.strokeStyle = layer === 'ndwi' ? 'rgba(180,240,255,0.85)' : 'rgba(180,220,255,0.25)';
        ctx.lineWidth = w;
        ctx.lineCap = 'round';
        ctx.lineJoin = 'round';
        ctx.stroke();
      });

      if (layer === 'risk' && rv.rk >= 4) {
        const n = rv.pts.length - 1;
        const t = animationPhase % 1;
        const i = Math.min(Math.floor(t * n), n - 1);
        const fr = t * n - i;
        const la = rv.pts[i][0] + fr * (rv.pts[Math.min(i + 1, n)][0] - rv.pts[i][0]);
        const lo = rv.pts[i][1] + fr * (rv.pts[Math.min(i + 1, n)][1] - rv.pts[i][1]);
        const [wx, wy] = p2c(la, lo, W, H);
        [0, 0.33, 0.66].forEach(off => {
          const rp = (animationPhase * 2.5 + off) % 1;
          ctx.beginPath();
          ctx.arc(wx, wy, rp * 22 + 4, 0, Math.PI * 2);
          ctx.strokeStyle = `rgba(226,75,74,${(1 - rp) * 0.7})`;
          ctx.lineWidth = 2;
          ctx.stroke();
        });
      }
    });

    // Cities
    CITIES.forEach(c => {
      const [x, y] = p2c(c.la, c.lo, W, H);
      ctx.beginPath();
      ctx.arc(x, y, 2, 0, Math.PI * 2);
      ctx.fillStyle = 'rgba(180,210,255,0.5)';
      ctx.fill();
      ctx.fillStyle = 'rgba(180,215,255,0.72)';
      ctx.font = '10px sans-serif';
      ctx.fillText(c.n, x + 6, y + 3);
    });

    // Stations
    ST.forEach(st => {
      const [x, y] = p2c(st.la, st.lo, W, H);
      const isSel = selectedStation && selectedStation.id === st.id;
      const col = RC[st.rk];

      if (isSel) {
        ctx.beginPath();
        ctx.arc(x, y, 14, 0, Math.PI * 2);
        ctx.fillStyle = col + '28';
        ctx.fill();
      }

      if (st.rk >= 5) {
        const pv = Math.sin(animationPhase * 9) * 0.5 + 0.5;
        ctx.beginPath();
        ctx.arc(x, y, 12 + pv * 9, 0, Math.PI * 2);
        ctx.strokeStyle = `rgba(226,75,74,${0.5 * (1 - pv)})`;
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      ctx.beginPath();
      ctx.arc(x, y, isSel ? 8 : 5.5, 0, Math.PI * 2);
      ctx.fillStyle = col;
      ctx.fill();
      ctx.strokeStyle = 'rgba(255,255,255,0.9)';
      ctx.lineWidth = isSel ? 2 : 1.2;
      ctx.stroke();
    });
  };

  // Initialize
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    setStations(ST);
    setSelectedStation(ST[0]);
    fetchAlert(ST[0]);
  }, []);

  // Animation loop
  useEffect(() => {
    let animId;
    const animate = () => {
      setAnimationPhase(prev => prev + 0.007);
      animId = requestAnimationFrame(animate);
    };
    animId = requestAnimationFrame(animate);
    return () => cancelAnimationFrame(animId);
  }, []);

  // Draw map when dependencies change
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    drawMap();
  }, [animationPhase, layer, selectedStation]);

  // Handle canvas resize
  // eslint-disable-next-line react-hooks/exhaustive-deps
  useEffect(() => {
    const handleResize = () => {
      const canvas = canvasRef.current;
      const mapWrap = mapWrapRef.current;
      if (canvas && mapWrap) {
        canvas.width = mapWrap.clientWidth;
        canvas.height = mapWrap.clientHeight;
        drawMap();
      }
    };

    handleResize();
    window.addEventListener('resize', handleResize);
    return () => window.removeEventListener('resize', handleResize);
  }, [layer, selectedStation]);

  const handleCanvasMouseMove = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const mx = e.clientX - rect.left;
    const my = e.clientY - rect.top;

    const [la, lo] = c2p(mx, my, canvas.width, canvas.height);
    setCoordinates(`${la.toFixed(3)}°N  ${lo.toFixed(3)}°E`);

    let closest = null;
    let minDist = 0.2;
    ST.forEach(st => {
      const d = Math.abs(st.la - la) + Math.abs(st.lo - lo);
      if (d < minDist) {
        minDist = d;
        closest = st;
      }
    });

    if (closest) {
      setHoveredStation(closest);
      setTipPos({ x: Math.min(mx + 14, canvas.width - 178), y: Math.max(my - 95, 8) });
      canvas.style.cursor = 'pointer';
    } else {
      setHoveredStation(null);
      canvas.style.cursor = 'crosshair';
    }
  };

  const handleCanvasClick = (e) => {
    const canvas = canvasRef.current;
    const rect = canvas.getBoundingClientRect();
    const [la, lo] = c2p(e.clientX - rect.left, e.clientY - rect.top, canvas.width, canvas.height);

    let closest = null;
    let minDist = 0.2;
    ST.forEach(st => {
      const d = Math.abs(st.la - la) + Math.abs(st.lo - lo);
      if (d < minDist) {
        minDist = d;
        closest = st;
      }
    });

    if (closest) {
      setSelectedStation(closest);
      fetchAlert(closest);
    }
  };

  const fetchAlert = async (station) => {
    setLoading(true);
    try {
      const alertData = await api.getStationAlert(station.id, { days_back: 3 });
      setAlert(alertData);
    } catch (err) {
      console.error('Error fetching alert:', err);
      setAlert(null);
    }
    setLoading(false);
  };

  const styles = `
    * { box-sizing: border-box; margin: 0; padding: 0; }
    body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #040d1a; color: #e0eeff; height: 100vh; overflow: hidden; display: flex; flex-direction: column; }
    .bar { display: flex; align-items: center; gap: 10px; padding: 8px 14px; background: #071828; border-bottom: 1px solid #0d2540; flex-shrink: 0; }
    .logo { font-size: 14px; font-weight: 600; letter-spacing: .03em; color: #cce4ff; }
    .logo b { color: #1a8fe3; }
    .sub { font-size: 11px; color: #4d7fa8; }
    .lbtns { display: flex; gap: 4px; margin-left: auto; }
    .lb { font-size: 11px; padding: 4px 11px; border-radius: 6px; border: 1px solid #1a3a5c; background: transparent; color: #6da3cc; cursor: pointer; transition: all .15s; }
    .lb.on { background: #1a8fe3; color: #fff; border-color: #1a8fe3; }
    .abar { background: #3d0a0a; color: #ff9999; font-size: 11px; padding: 5px 14px; display: flex; align-items: center; gap: 8px; border-bottom: 1px solid #5a1010; flex-shrink: 0; }
    .dot { width: 6px; height: 6px; border-radius: 50%; background: #ff5050; animation: blink 1s infinite; flex-shrink: 0; }
    @keyframes blink { 0%, 100% { opacity: 1; } 50% { opacity: .2; } }
    .body { display: flex; flex: 1; overflow: hidden; }
    .mapwrap { flex: 1; position: relative; overflow: hidden; }
    canvas { position: absolute; top: 0; left: 0; width: 100%; height: 100%; cursor: crosshair; }
    .side { width: 230px; display: flex; flex-direction: column; background: #071828; border-left: 1px solid #0d2540; flex-shrink: 0; }
    .sh { font-size: 10px; font-weight: 600; color: #4d7fa8; text-transform: uppercase; letter-spacing: .09em; padding: 9px 12px 5px; border-bottom: 1px solid #0d2540; }
    .slist { flex: 1; overflow-y: auto; }
    .slist::-webkit-scrollbar { width: 3px; }
    .slist::-webkit-scrollbar-track { background: #050e1e; }
    .slist::-webkit-scrollbar-thumb { background: #1a3a5c; }
    .si { padding: 8px 12px; border-bottom: 1px solid #0a1e35; cursor: pointer; transition: background .1s; }
    .si:hover { background: #0d2540; }
    .si.sel { background: #0e2a45; border-left: 2px solid #1a8fe3; }
    .si-id { font-size: 9px; font-weight: 700; font-family: monospace; }
    .si-n { font-size: 11px; color: #b8d8f0; margin-top: 1px; line-height: 1.3; }
    .si-r { font-size: 10px; margin-top: 2px; }
    .dpane { border-top: 1px solid #0d2540; padding: 10px 12px; background: #050e1e; flex-shrink: 0; }
    .dn { font-size: 11px; font-weight: 600; margin-bottom: 7px; color: #cce4ff; line-height: 1.3; }
    .dr { display: flex; justify-content: space-between; font-size: 10px; margin-bottom: 3px; align-items: flex-start; }
    .dl { color: #4d7fa8; }
    .dv { font-family: monospace; font-size: 10px; color: #90c4e8; text-align: right; max-width: 115px; line-height: 1.4; }
    .abtn { width: 100%; margin-top: 9px; font-size: 11px; padding: 7px; border-radius: 6px; background: #1a8fe3; color: #fff; border: none; cursor: pointer; font-weight: 600; letter-spacing: .02em; }
    .abtn:hover { background: #1a7fd0; }
    .leg { position: absolute; bottom: 10px; left: 10px; background: rgba(4,13,26,0.92); border-radius: 8px; padding: 8px 11px; border: 1px solid #0d2540; }
    .lr { display: flex; align-items: center; gap: 6px; font-size: 10px; color: #8ab8d8; margin-bottom: 3px; }
    .lr:last-child { margin-bottom: 0; }
    .ld { width: 8px; height: 8px; border-radius: 50%; flex-shrink: 0; }
    .s2b { position: absolute; top: 10px; right: 10px; background: rgba(4,13,26,0.92); border-radius: 8px; padding: 5px 10px; font-size: 10px; color: #5fa8d8; border: 1px solid #0d2540; }
    .crds { position: absolute; bottom: 10px; right: 10px; background: rgba(4,13,26,0.92); border-radius: 6px; padding: 3px 8px; font-size: 10px; font-family: monospace; color: #5fa8d8; border: 1px solid #0d2540; }
    .tip { position: absolute; background: #071828; border: 1px solid #1a3a5c; border-radius: 8px; padding: 9px 11px; width: 170px; z-index: 10; pointer-events: none; display: none; box-shadow: 0 4px 16px rgba(0,0,0,.6); }
    .tip.show { display: block; }
    .tip-id { font-size: 9px; font-family: monospace; font-weight: 700; }
    .tip-n { font-size: 11px; font-weight: 600; margin: 2px 0 6px; line-height: 1.3; color: #cce4ff; }
    .tip-row { display: flex; justify-content: space-between; font-size: 10px; margin-bottom: 2px; color: #6da3cc; }
    .tip-row span { font-family: monospace; color: #90c4e8; }
  `;

  return (
    <div style={{ fontFamily: '-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif', background: '#040d1a', color: '#e0eeff', height: '100vh', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
      <style>{styles}</style>

      {/* Header bar */}
      <div className="bar">
        <div className="logo">WATER<b>WATCH</b></div>
        <div className="sub">Sentinel-2 L2A · Vardar Basin · 2026-04-25 · ☁ 3%</div>
        <div className="lbtns">
          <button className={`lb ${layer === 'sat' ? 'on' : ''}`} onClick={() => setLayer('sat')}>Satellite</button>
          <button className={`lb ${layer === 'ndwi' ? 'on' : ''}`} onClick={() => setLayer('ndwi')}>NDWI water</button>
          <button className={`lb ${layer === 'risk' ? 'on' : ''}`} onClick={() => setLayer('risk')}>Risk overlay</button>
        </div>
      </div>

      {/* Alert bar */}
      {alert && (
        <div className="abar">
          <div className="dot"></div>
          <strong>LIVE</strong>&nbsp;
          {alert.alert_type === 'critical' 
            ? `Upstream anomaly detected — ${alert.satellite_signal.sigma.toFixed(1)}σ above baseline — Est. arrival ${alert.movement_model.target_location}: ${Math.round(alert.movement_model.estimated_arrival_minutes)} min`
            : `Data: ${alert.station_id} · Confidence: ${(alert.confidence * 100).toFixed(0)}%`
          }
        </div>
      )}

      {/* Main body */}
      <div className="body">
        <div className="mapwrap" ref={mapWrapRef}>
          <canvas
            ref={canvasRef}
            onMouseMove={handleCanvasMouseMove}
            onClick={handleCanvasClick}
            style={{ position: 'absolute', top: 0, left: 0, width: '100%', height: '100%' }}
          />
          <div className="s2b">Sentinel-2 L2A · ☁ 3%</div>
          <div className="crds">{coordinates}</div>
          <div className="leg">
            <div className="lr"><div className="ld" style={{ background: '#E24B4A' }} />Critical (5/5)</div>
            <div className="lr"><div className="ld" style={{ background: '#EF9F27' }} />Very high (4/5)</div>
            <div className="lr"><div className="ld" style={{ background: '#a8c340' }} />High (3/5)</div>
            <div className="lr"><div className="ld" style={{ background: '#3db87a' }} />Moderate (2/5)</div>
            <div className="lr"><div className="ld" style={{ background: '#3a80c0' }} />Water surface</div>
          </div>

          {/* Tooltip */}
          {hoveredStation && (
            <div className="tip show" style={{ left: tipPos.x + 'px', top: tipPos.y + 'px' }}>
              <div className="tip-id" style={{ color: RC[hoveredStation.rk] }}>{hoveredStation.id} · {hoveredStation.r}</div>
              <div className="tip-n">{hoveredStation.n}</div>
              <div className="tip-row">Risk <span>{RL[hoveredStation.rk]}</span></div>
              <div className="tip-row">Sigma <span>{hoveredStation.sg.toFixed(1)}σ</span></div>
              <div className="tip-row">WFD <span>{hoveredStation.wfd}</span></div>
              <div className="tip-row">Source <span style={{ maxWidth: '90px', textAlign: 'right', display: 'inline-block', lineHeight: '1.3' }}>{hoveredStation.src}</span></div>
            </div>
          )}
        </div>

        {/* Sidebar */}
        <div className="side">
          <div className="sh">Monitoring stations ({stations.length})</div>
          <div className="slist">
            {stations.map(st => (
              <div
                key={st.id}
                className={`si ${selectedStation?.id === st.id ? 'sel' : ''}`}
                onClick={() => {
                  setSelectedStation(st);
                  fetchAlert(st);
                }}
              >
                <div className="si-id" style={{ color: RC[st.rk] }}>{st.id}</div>
                <div className="si-n">{st.n}</div>
                <div className="si-r" style={{ color: RC[st.rk] }}>{RL[st.rk]}</div>
              </div>
            ))}
          </div>

          {/* Details pane */}
          <div className="dpane">
            <div className="dn">{selectedStation ? selectedStation.n : 'Select a station'}</div>
            {selectedStation && (
              <>
                <div className="dr"><span className="dl">Risk</span><span className="dv">{RL[selectedStation.rk]}</span></div>
                <div className="dr"><span className="dl">Parameters</span><span className="dv">{selectedStation.par}</span></div>
                <div className="dr"><span className="dl">EU WFD</span><span className="dv">{selectedStation.wfd}</span></div>
                <div className="dr"><span className="dl">Sigma deviation</span><span className="dv">σ = {selectedStation.sg.toFixed(1)} · conf {Math.min(98, Math.round(60 + selectedStation.sg * 8))}%</span></div>
                <div className="dr"><span className="dl">Coordinates</span><span className="dv">{selectedStation.la.toFixed(3)}°N {selectedStation.lo.toFixed(3)}°E</span></div>
              </>
            )}
            <button className="abtn" onClick={() => alert('In live version: opens data scrape for this station')} disabled={loading}>
              {loading ? 'Loading...' : 'Scrape Sentinel-2 for this point →'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default WaterWatchMap;
